    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n/*\n * sparse memory mappings.\n */\n#include <linux/mm.h>\n#include <linux/slab.h>\n#include <linux/mmzone.h>\n#include <linux/memblock.h>\n#include <linux/compiler.h>\n#include <linux/highmem.h>\n#include <linux/export.h>\n#include <linux/spinlock.h>\n#include <linux/vmalloc.h>\n#include <linux/swap.h>\n#include <linux/swapops.h>\n#include <linux/bootmem_info.h>\n#include <linux/vmstat.h>\n#include \"internal.h\"\n#include <asm/dma.h>\n\n/*\n * Permanent SPARSEMEM data:\n *\n * 1) mem_section\t- memory sections, mem_map's for valid memory\n */\n#ifdef CONFIG_SPARSEMEM_EXTREME\nstruct mem_section **mem_section;\n#else\nstruct mem_section mem_section[NR_SECTION_ROOTS][SECTIONS_PER_ROOT]\n\t____cacheline_internodealigned_in_smp;\n#endif\nEXPORT_SYMBOL(mem_section);\n\n#ifdef NODE_NOT_IN_PAGE_FLAGS\n/*\n * If we did not store the node number in the page then we have to\n * do a lookup in the section_to_node_table in order to find which\n * node the page belongs to.\n */\n#if MAX_NUMNODES <= 256\nstatic u8 section_to_node_table[NR_MEM_SECTIONS] __cacheline_aligned;\n#else\nstatic u16 section_to_node_table[NR_MEM_SECTIONS] __cacheline_aligned;\n#endif\n\nint memdesc_nid(memdesc_flags_t mdf)\n{\n\treturn section_to_node_table[memdesc_section(mdf)];\n}\nEXPORT_SYMBOL(memdesc_nid);\n\nstatic void set_section_nid(unsigned long section_nr, int nid)\n{\n\tsection_to_node_table[section_nr] = nid;\n}\n#else /* !NODE_NOT_IN_PAGE_FLAGS */\nstatic inline void set_section_nid(unsigned long section_nr, int nid)\n{\n}\n#endif\n\n#ifdef CONFIG_SPARSEMEM_EXTREME\nstatic noinline struct mem_section __ref *sparse_index_alloc(int nid)\n{\n\tstruct mem_section *section = NULL;\n\tunsigned long array_size = SECTIONS_PER_ROOT *\n\t\t\t\t   sizeof(struct mem_section);\n\n\tif (slab_is_available()) {\n\t\tsection = kzalloc_node(array_size, GFP_KERNEL, nid);\n\t} else {\n\t\tsection = memblock_alloc_node(array_size, SMP_CACHE_BYTES,\n\t\t\t\t\t      nid);\n\t\tif (!section)\n\t\t\tpanic(\"%s: Failed to allocate %lu bytes nid=%d\\n\",\n\t\t\t      __func__, array_size, nid);\n\t}\n\n\treturn section;\n}\n\nstatic int __meminit sparse_index_init(unsigned long section_nr, int nid)\n{\n\tunsigned long root = SECTION_NR_TO_ROOT(section_nr);\n\tstruct mem_section *section;\n\n\t/*\n\t * An existing section is possible in the sub-section hotplug\n\t * case. First hot-add instantiates, follow-on hot-add reuses\n\t * the existing section.\n\t *\n\t * The mem_hotplug_lock resolves the apparent race below.\n\t */\n\tif (mem_section[root])\n\t\treturn 0;\n\n\tsection = sparse_index_alloc(nid);\n\tif (!section)\n\t\treturn -ENOMEM;\n\n\tmem_section[root] = section;\n\n\treturn 0;\n}\n#else /* !SPARSEMEM_EXTREME */\nstatic inline int sparse_index_init(unsigned long section_nr, int nid)\n{\n\treturn 0;\n}\n#endif\n\n/*\n * During early boot, before section_mem_map is used for an actual\n * mem_map, we use section_mem_map to store the section's NUMA\n * node.  This keeps us from having to use another data structure.  The\n * node information is cleared just before we store the real mem_map.\n */\nstatic inline unsigned long sparse_encode_early_nid(int nid)\n{\n\treturn ((unsigned long)nid << SECTION_NID_SHIFT);\n}\n\nstatic inline int sparse_early_nid(struct mem_section *section)\n{\n\treturn (section->section_mem_map >> SECTION_NID_SHIFT);\n}\n\n/* Validate the physical addressing limitations of the model */\nstatic void __meminit mminit_validate_memmodel_limits(unsigned long *start_pfn,\n\t\t\t\t\t\tunsigned long *end_pfn)\n{\n\tunsigned long max_sparsemem_pfn = (DIRECT_MAP_PHYSMEM_END + 1) >> PAGE_SHIFT;\n\n\t/*\n\t * Sanity checks - do not allow an architecture to pass\n\t * in larger pfns than the maximum scope of sparsemem:\n\t */\n\tif (*start_pfn > max_sparsemem_pfn) {\n\t\tmminit_dprintk(MMINIT_WARNING, \"pfnvalidation\",\n\t\t\t\"Start of range %lu -> %lu exceeds SPARSEMEM max %lu\\n\",\n\t\t\t*start_pfn, *end_pfn, max_sparsemem_pfn);\n\t\tWARN_ON_ONCE(1);\n\t\t*start_pfn = max_sparsemem_pfn;\n\t\t*end_pfn = max_sparsemem_pfn;\n\t} else if (*end_pfn > max_sparsemem_pfn) {\n\t\tmminit_dprintk(MMINIT_WARNING, \"pfnvalidation\",\n\t\t\t\"End of range %lu -> %lu exceeds SPARSEMEM max %lu\\n\",\n\t\t\t*start_pfn, *end_pfn, max_sparsemem_pfn);\n\t\tWARN_ON_ONCE(1);\n\t\t*end_pfn = max_sparsemem_pfn;\n\t}\n}\n\n/*\n * There are a number of times that we loop over NR_MEM_SECTIONS,\n * looking for section_present() on each.  But, when we have very\n * large physical address spaces, NR_MEM_SECTIONS can also be\n * very large which makes the loops quite long.\n *\n * Keeping track of this gives us an easy way to break out of\n * those loops early.\n */\nunsigned long __highest_present_section_nr;\n\nstatic inline unsigned long first_present_section_nr(void)\n{\n\treturn next_present_section_nr(-1);\n}\n\n#ifdef CONFIG_SPARSEMEM_VMEMMAP\nstatic void subsection_mask_set(unsigned long *map, unsigned long pfn,\n\t\tunsigned long nr_pages)\n{\n\tint idx = subsection_map_index(pfn);\n\tint end = subsection_map_index(pfn + nr_pages - 1);\n\n\tbitmap_set(map, idx, end - idx + 1);\n}\n\nvoid __init sparse_init_subsection_map(unsigned long pfn, unsigned long nr_pages)\n{\n\tint end_sec_nr = pfn_to_section_nr(pfn + nr_pages - 1);\n\tunsigned long nr, start_sec_nr = pfn_to_section_nr(pfn);\n\n\tfor (nr = start_sec_nr; nr <= end_sec_nr; nr++) {\n\t\tstruct mem_section *ms;\n\t\tunsigned long pfns;\n\n\t\tpfns = min(nr_pages, PAGES_PER_SECTION\n\t\t\t\t- (pfn & ~PAGE_SECTION_MASK));\n\t\tms = __nr_to_section(nr);\n\t\tsubsection_mask_set(ms->usage->subsection_map, pfn, pfns);\n\n\t\tpr_debug(\"%s: sec: %lu pfns: %lu set(%d, %d)\\n\", __func__, nr,\n\t\t\t\tpfns, subsection_map_index(pfn),\n\t\t\t\tsubsection_map_index(pfn + pfns - 1));\n\n\t\tpfn += pfns;\n\t\tnr_pages -= pfns;\n\t}\n}\n#endif\n\n/* Record a memory area against a node. */\nstatic void __init memory_present(int nid, unsigned long start, unsigned long end)\n{\n\tunsigned long pfn;\n\n\tstart &= PAGE_SECTION_MASK;\n\tmminit_validate_memmodel_limits(&start, &end);\n\tfor (pfn = start; pfn < end; pfn += PAGES_PER_SECTION) {\n\t\tunsigned long section_nr = pfn_to_section_nr(pfn);\n\t\tstruct mem_section *ms;\n\n\t\tsparse_index_init(section_nr, nid);\n\t\tset_section_nid(section_nr, nid);\n\n\t\tms = __nr_to_section(section_nr);\n\t\tif (!ms->section_mem_map) {\n\t\t\tms->section_mem_map = sparse_encode_early_nid(nid) |\n\t\t\t\t\t\t\tSECTION_IS_ONLINE;\n\t\t\t__section_mark_present(ms, section_nr);\n\t\t}\n\t}\n}\n\n/*\n * Mark all memblocks as present using memory_present().\n * This is a convenience function that is useful to mark all of the systems\n * memory as present during initialization.\n */\nstatic void __init memblocks_present(void)\n{\n\tunsigned long start, end;\n\tint i, nid;\n\n#ifdef CONFIG_SPARSEMEM_EXTREME\n\tif (unlikely(!mem_section)) {\n\t\tunsigned long size, align;\n\n\t\tsize = sizeof(struct mem_section *) * NR_SECTION_ROOTS;\n\t\talign = 1 << (INTERNODE_CACHE_SHIFT);\n\t\tmem_section = memblock_alloc_or_panic(size, align);\n\t}\n#endif\n\n\tfor_each_mem_pfn_range(i, MAX_NUMNODES, &start, &end, &nid)\n\t\tmemory_present(nid, start, end);\n}\n\nstatic unsigned long usemap_size(void)\n{\n\treturn BITS_TO_LONGS(SECTION_BLOCKFLAGS_BITS) * sizeof(unsigned long);\n}\n\nsize_t mem_section_usage_size(void)\n{\n\treturn sizeof(struct mem_section_usage) + usemap_size();\n}\n\n#ifdef CONFIG_SPARSEMEM_VMEMMAP\nunsigned long __init section_map_size(void)\n{\n\treturn ALIGN(sizeof(struct page) * PAGES_PER_SECTION, PMD_SIZE);\n}\n\n#else\nunsigned long __init section_map_size(void)\n{\n\treturn PAGE_ALIGN(sizeof(struct page) * PAGES_PER_SECTION);\n}\n\nstruct page __init *__populate_section_memmap(unsigned long pfn,\n\t\tunsigned long nr_pages, int nid, struct vmem_altmap *altmap,\n\t\tstruct dev_pagemap *pgmap)\n{\n\tunsigned long size = section_map_size();\n\tstruct page *map = sparse_buffer_alloc(size);\n\tphys_addr_t addr = __pa(MAX_DMA_ADDRESS);\n\n\tif (map)\n\t\treturn map;\n\n\tmap = memmap_alloc(size, size, addr, nid, false);\n\tif (!map)\n\t\tpanic(\"%s: Failed to allocate %lu bytes align=0x%lx nid=%d from=%pa\\n\",\n\t\t      __func__, size, PAGE_SIZE, nid, &addr);\n\n\treturn map;\n}\n#endif /* !CONFIG_SPARSEMEM_VMEMMAP */\n\nstatic void *sparsemap_buf __meminitdata;\nstatic void *sparsemap_buf_end __meminitdata;\n\nstatic inline void __meminit sparse_buffer_free(unsigned long size)\n{\n\tWARN_ON(!sparsemap_buf || size == 0);\n\tmemblock_free(sparsemap_buf, size);\n}\n\nstatic void __init sparse_buffer_init(unsigned long size, int nid)\n{\n\tphys_addr_t addr = __pa(MAX_DMA_ADDRESS);\n\tWARN_ON(sparsemap_buf);\t/* forgot to call sparse_buffer_fini()? */\n\t/*\n\t * Pre-allocated buffer is mainly used by __populate_section_memmap\n\t * and we want it to be properly aligned to the section size - this is\n\t * especially the case for VMEMMAP which maps memmap to PMDs\n\t */\n\tsparsemap_buf = memmap_alloc(size, section_map_size(), addr, nid, true);\n\tsparsemap_buf_end = sparsemap_buf + size;\n}\n\nstatic void __init sparse_buffer_fini(void)\n{\n\tunsigned long size = sparsemap_buf_end - sparsemap_buf;\n\n\tif (sparsemap_buf && size > 0)\n\t\tsparse_buffer_free(size);\n\tsparsemap_buf = NULL;\n}\n\nvoid * __meminit sparse_buffer_alloc(unsigned long size)\n{\n\tvoid *ptr = NULL;\n\n\tif (sparsemap_buf) {\n\t\tptr = (void *) roundup((unsigned long)sparsemap_buf, size);\n\t\tif (ptr + size > sparsemap_buf_end)\n\t\t\tptr = NULL;\n\t\telse {\n\t\t\t/* Free redundant aligned space */\n\t\t\tif ((unsigned long)(ptr - sparsemap_buf) > 0)\n\t\t\t\tsparse_buffer_free((unsigned long)(ptr - sparsemap_buf));\n\t\t\tsparsemap_buf = ptr + size;\n\t\t}\n\t}\n\treturn ptr;\n}\n\nvoid __weak __meminit vmemmap_populate_print_last(void)\n{\n}\n\nstatic void *sparse_usagebuf __meminitdata;\nstatic void *sparse_usagebuf_end __meminitdata;\n\n/*\n * Helper function that is used for generic section initialization, and\n * can also be used by any hooks added above.\n */\nvoid __init sparse_init_early_section(int nid, struct page *map,\n\t\t\t\t      unsigned long pnum, unsigned long flags)\n{\n\tBUG_ON(!sparse_usagebuf || sparse_usagebuf >= sparse_usagebuf_end);\n\tsparse_init_one_section(__nr_to_section(pnum), pnum, map,\n\t\t\tsparse_usagebuf, SECTION_IS_EARLY | flags);\n\tsparse_usagebuf = (void *)sparse_usagebuf + mem_section_usage_size();\n}\n\nstatic int __init sparse_usage_init(int nid, unsigned long map_count)\n{\n\tunsigned long size;\n\n\tsize = mem_section_usage_size() * map_count;\n\tsparse_usagebuf = memblock_alloc_node(size, SMP_CACHE_BYTES, nid);\n\tif (!sparse_usagebuf) {\n\t\tsparse_usagebuf_end = NULL;\n\t\treturn -ENOMEM;\n\t}\n\n\tsparse_usagebuf_end = sparse_usagebuf + size;\n\treturn 0;\n}\n\nstatic void __init sparse_usage_fini(void)\n{\n\tsparse_usagebuf = sparse_usagebuf_end = NULL;\n}\n\n/*\n * Initialize sparse on a specific node. The node spans [pnum_begin, pnum_end)\n * And number of present sections in this node is map_count.\n */\nstatic void __init sparse_init_nid(int nid, unsigned long pnum_begin,\n\t\t\t\t   unsigned long pnum_end,\n\t\t\t\t   unsigned long map_count)\n{\n\tunsigned long pnum;\n\tstruct page *map;\n\tstruct mem_section *ms;\n\n\tif (sparse_usage_init(nid, map_count)) {\n\t\tpr_err(\"%s: node[%d] usemap allocation failed\", __func__, nid);\n\t\tgoto failed;\n\t}\n\n\tsparse_buffer_init(map_count * section_map_size(), nid);\n\n\tsparse_vmemmap_init_nid_early(nid);\n\n\tfor_each_present_section_nr(pnum_begin, pnum) {\n\t\tunsigned long pfn = section_nr_to_pfn(pnum);\n\n\t\tif (pnum >= pnum_end)\n\t\t\tbreak;\n\n\t\tms = __nr_to_section(pnum);\n\t\tif (!preinited_vmemmap_section(ms)) {\n\t\t\tmap = __populate_section_memmap(pfn, PAGES_PER_SECTION,\n\t\t\t\t\tnid, NULL, NULL);\n\t\t\tif (!map) {\n\t\t\t\tpr_err(\"%s: node[%d] memory map backing failed. Some memory will not be available.\",\n\t\t\t\t       __func__, nid);\n\t\t\t\tpnum_begin = pnum;\n\t\t\t\tsparse_usage_fini();\n\t\t\t\tsparse_buffer_fini();\n\t\t\t\tgoto failed;\n\t\t\t}\n\t\t\tmemmap_boot_pages_add(DIV_ROUND_UP(PAGES_PER_SECTION * sizeof(struct page),\n\t\t\t\t\t\t\t   PAGE_SIZE));\n\t\t\tsparse_init_early_section(nid, map, pnum, 0);\n\t\t}\n\t}\n\tsparse_usage_fini();\n\tsparse_buffer_fini();\n\treturn;\nfailed:\n\t/*\n\t * We failed to allocate, mark all the following pnums as not present,\n\t * except the ones already initialized earlier.\n\t */\n\tfor_each_present_section_nr(pnum_begin, pnum) {\n\t\tif (pnum >= pnum_end)\n\t\t\tbreak;\n\t\tms = __nr_to_section(pnum);\n\t\tif (!preinited_vmemmap_section(ms))\n\t\t\tms->section_mem_map = 0;\n\t\tms->section_mem_map = 0;\n\t}\n}\n\n/*\n * Allocate the accumulated non-linear sections, allocate a mem_map\n * for each and record the physical to section mapping.\n */\nvoid __init sparse_init(void)\n{\n\tunsigned long pnum_end, pnum_begin, map_count = 1;\n\tint nid_begin;\n\n\t/* see include/linux/mmzone.h 'struct mem_section' definition */\n\tBUILD_BUG_ON(!is_power_of_2(sizeof(struct mem_section)));\n\tmemblocks_present();\n\n\tif (compound_info_has_mask()) {\n\t\tVM_WARN_ON_ONCE(!IS_ALIGNED((unsigned long) pfn_to_page(0),\n\t\t\t\t    MAX_FOLIO_VMEMMAP_ALIGN));\n\t}\n\n\tpnum_begin = first_present_section_nr();\n\tnid_begin = sparse_early_nid(__nr_to_section(pnum_begin));\n\n\t/* Setup pageblock_order for HUGETLB_PAGE_SIZE_VARIABLE */\n\tset_pageblock_order();\n\n\tfor_each_present_section_nr(pnum_begin + 1, pnum_end) {\n\t\tint nid = sparse_early_nid(__nr_to_section(pnum_end));\n\n\t\tif (nid == nid_begin) {\n\t\t\tmap_count++;\n\t\t\tcontinue;\n\t\t}\n\t\t/* Init node with sections in range [pnum_begin, pnum_end) */\n\t\tsparse_init_nid(nid_begin, pnum_begin, pnum_end, map_count);\n\t\tnid_begin = nid;\n\t\tpnum_begin = pnum_end;\n\t\tmap_count = 1;\n\t}\n\t/* cover the last node */\n\tsparse_init_nid(nid_begin, pnum_begin, pnum_end, map_count);\n\tvmemmap_populate_print_last();\n}\n\n#ifdef CONFIG_MEMORY_HOTPLUG\n\n/* Mark all memory sections within the pfn range as online */\nvoid online_mem_sections(unsigned long start_pfn, unsigned long end_pfn)\n{\n\tunsigned long pfn;\n\n\tfor (pfn = start_pfn; pfn < end_pfn; pfn += PAGES_PER_SECTION) {\n\t\tunsigned long section_nr = pfn_to_section_nr(pfn);\n\t\tstruct mem_section *ms = __nr_to_section(section_nr);\n\n\t\tms->section_mem_map |= SECTION_IS_ONLINE;\n\t}\n}\n\n/* Mark all memory sections within the pfn range as offline */\nvoid offline_mem_sections(unsigned long start_pfn, unsigned long end_pfn)\n{\n\tunsigned long pfn;\n\n\tfor (pfn = start_pfn; pfn < end_pfn; pfn += PAGES_PER_SECTION) {\n\t\tunsigned long section_nr = pfn_to_section_nr(pfn);\n\t\tstruct mem_section *ms = __nr_to_section(section_nr);\n\n\t\tms->section_mem_map &= ~SECTION_IS_ONLINE;\n\t}\n}\n\nstatic struct page * __meminit populate_section_memmap(unsigned long pfn,\n\t\tunsigned long nr_pages, int nid, struct vmem_altmap *altmap,\n\t\tstruct dev_pagemap *pgmap)\n{\n\treturn __populate_section_memmap(pfn, nr_pages, nid, altmap, pgmap);\n}\n\nstatic void depopulate_section_memmap(unsigned long pfn, unsigned long nr_pages,\n\t\tstruct vmem_altmap *altmap)\n{\n\tunsigned long start = (unsigned long) pfn_to_page(pfn);\n\tunsigned long end = start + nr_pages * sizeof(struct page);\n\n\tvmemmap_free(start, end, altmap);\n}\nstatic void free_map_bootmem(struct page *memmap)\n{\n\tunsigned long start = (unsigned long)memmap;\n\tunsigned long end = (unsigned long)(memmap + PAGES_PER_SECTION);\n\n\tvmemmap_free(start, end, NULL);\n}\n\nstatic int clear_subsection_map(unsigned long pfn, unsigned long nr_pages)\n{\n\tDECLARE_BITMAP(map, SUBSECTIONS_PER_SECTION) = { 0 };\n\tDECLARE_BITMAP(tmp, SUBSECTIONS_PER_SECTION) = { 0 };\n\tstruct mem_section *ms = __pfn_to_section(pfn);\n\tunsigned long *subsection_map = ms->usage\n\t\t? &ms->usage->subsection_map[0] : NULL;\n\n\tsubsection_mask_set(map, pfn, nr_pages);\n\tif (subsection_map)\n\t\tbitmap_and(tmp, map, subsection_map, SUBSECTIONS_PER_SECTION);\n\n\tif (WARN(!subsection_map || !bitmap_equal(tmp, map, SUBSECTIONS_PER_SECTION),\n\t\t\t\t\"section already deactivated (%#lx + %ld)\\n\",\n\t\t\t\tpfn, nr_pages))\n\t\treturn -EINVAL;\n\n\tbitmap_xor(subsection_map, map, subsection_map, SUBSECTIONS_PER_SECTION);\n\treturn 0;\n}\n\nstatic bool is_subsection_map_empty(struct mem_section *ms)\n{\n\treturn bitmap_empty(&ms->usage->subsection_map[0],\n\t\t\t    SUBSECTIONS_PER_SECTION);\n}\n\nstatic int fill_subsection_map(unsigned long pfn, unsigned long nr_pages)\n{\n\tstruct mem_section *ms = __pfn_to_section(pfn);\n\tDECLARE_BITMAP(map, SUBSECTIONS_PER_SECTION) = { 0 };\n\tunsigned long *subsection_map;\n\tint rc = 0;\n\n\tsubsection_mask_set(map, pfn, nr_pages);\n\n\tsubsection_map = &ms->usage->subsection_map[0];\n\n\tif (bitmap_empty(map, SUBSECTIONS_PER_SECTION))\n\t\trc = -EINVAL;\n\telse if (bitmap_intersects(map, subsection_map, SUBSECTIONS_PER_SECTION))\n\t\trc = -EEXIST;\n\telse\n\t\tbitmap_or(subsection_map, map, subsection_map,\n\t\t\t\tSUBSECTIONS_PER_SECTION);\n\n\treturn rc;\n}\n\n/*\n * To deactivate a memory region, there are 3 cases to handle across\n * two configurations (SPARSEMEM_VMEMMAP={y,n}):\n *\n * 1. deactivation of a partial hot-added section (only possible in\n *    the SPARSEMEM_VMEMMAP=y case).\n *      a) section was present at memory init.\n *      b) section was hot-added post memory init.\n * 2. deactivation of a complete hot-added section.\n * 3. deactivation of a complete section from memory init.\n *\n * For 1, when subsection_map does not empty we will not be freeing the\n * usage map, but still need to free the vmemmap range.\n *\n * For 2 and 3, the SPARSEMEM_VMEMMAP={y,n} cases are unified\n */\nstatic void section_deactivate(unsigned long pfn, unsigned long nr_pages,\n\t\tstruct vmem_altmap *altmap)\n{\n\tstruct mem_section *ms = __pfn_to_section(pfn);\n\tbool section_is_early = early_section(ms);\n\tstruct page *memmap = NULL;\n\tbool empty;\n\n\tif (clear_subsection_map(pfn, nr_pages))\n\t\treturn;\n\n\tempty = is_subsection_map_empty(ms);\n\tif (empty) {\n\t\t/*\n\t\t * Mark the section invalid so that valid_section()\n\t\t * return false. This prevents code from dereferencing\n\t\t * ms->usage array.\n\t\t */\n\t\tms->section_mem_map &= ~SECTION_HAS_MEM_MAP;\n\n\t\t/*\n\t\t * When removing an early section, the usage map is kept (as the\n\t\t * usage maps of other sections fall into the same page). It\n\t\t * will be re-used when re-adding the section - which is then no\n\t\t * longer an early section. If the usage map is PageReserved, it\n\t\t * was allocated during boot.\n\t\t */\n\t\tif (!PageReserved(virt_to_page(ms->usage))) {\n\t\t\tkfree_rcu(ms->usage, rcu);\n\t\t\tWRITE_ONCE(ms->usage, NULL);\n\t\t}\n\t\tmemmap = pfn_to_page(SECTION_ALIGN_DOWN(pfn));\n\t}\n\n\t/*\n\t * The memmap of early sections is always fully populated. See\n\t * section_activate() and pfn_valid() .\n\t */\n\tif (!section_is_early) {\n\t\tmemmap_pages_add(-1L * (DIV_ROUND_UP(nr_pages * sizeof(struct page), PAGE_SIZE)));\n\t\tdepopulate_section_memmap(pfn, nr_pages, altmap);\n\t} else if (memmap) {\n\t\tmemmap_boot_pages_add(-1L * (DIV_ROUND_UP(nr_pages * sizeof(struct page),\n\t\t\t\t\t\t\t  PAGE_SIZE)));\n\t\tfree_map_bootmem(memmap);\n\t}\n\n\tif (empty)\n\t\tms->section_mem_map = (unsigned long)NULL;\n}\n\nstatic struct page * __meminit section_activate(int nid, unsigned long pfn,\n\t\tunsigned long nr_pages, struct vmem_altmap *altmap,\n\t\tstruct dev_pagemap *pgmap)\n{\n\tstruct mem_section *ms = __pfn_to_section(pfn);\n\tstruct mem_section_usage *usage = NULL;\n\tstruct page *memmap;\n\tint rc;\n\n\tif (!ms->usage) {\n\t\tusage = kzalloc(mem_section_usage_size(), GFP_KERNEL);\n\t\tif (!usage)\n\t\t\treturn ERR_PTR(-ENOMEM);\n\t\tms->usage = usage;\n\t}\n\n\trc = fill_subsection_map(pfn, nr_pages);\n\tif 