depends on ZSMALLOC\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  132) \n2ccd9fecd9163 (Johannes Weiner             2025-08-29 17:15:27 +0100  133) comment \"Zsmalloc is a common backend allocator for zswap & zram\"\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  134) \n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  135) config ZSMALLOC_STAT\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  136) \tbool \"Export zsmalloc statistics\"\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  137) \tselect DEBUG_FS\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  138) \thelp\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  139) \t  This option enables code in the zsmalloc to collect various\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  140) \t  statistics about what's happening in zsmalloc and exports that\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  141) \t  information to userspace via debugfs.\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  142) \t  If unsure, say N.\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  143) \n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  144) config ZSMALLOC_CHAIN_SIZE\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  145) \tint \"Maximum number of physical pages per-zspage\"\nb46402fa894f8 (Sergey Senozhatsky          2023-01-18 09:52:10 +0900  146) \tdefault 8\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  147) \trange 4 16\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  148) \thelp\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  149) \t  This option sets the upper limit on the number of physical pages\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  150) \t  that a zmalloc page (zspage) can consist of. The optimal zspage\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  151) \t  chain size is calculated for each size class during the\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  152) \t  initialization of the pool.\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  153) \n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  154) \t  Changing this option can alter the characteristics of size classes,\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  155) \t  such as the number of pages per zspage and the number of objects\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  156) \t  per zspage. This can also result in different configurations of\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  157) \t  the pool, as zsmalloc merges size classes with similar\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  158) \t  characteristics.\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  159) \n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  160) \t  For more information, see zsmalloc documentation.\n4ff93b292c0b9 (Sergey Senozhatsky          2023-01-18 09:52:09 +0900  161) \n2ccd9fecd9163 (Johannes Weiner             2025-08-29 17:15:27 +0100  162) endmenu\n2ccd9fecd9163 (Johannes Weiner             2025-08-29 17:15:27 +0100  163) \n2ccd9fecd9163 (Johannes Weiner             2025-08-29 17:15:27 +0100  164) endif\n2ccd9fecd9163 (Johannes Weiner             2025-08-29 17:15:27 +0100  165) \n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  166) menu \"Slab allocator options\"\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  167) \n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  168) config SLUB\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  169) \tdef_bool y\naf92793e52c3a (Alexei Starovoitov          2025-09-08 18:00:07 -0700  170) \tselect IRQ_WORK\neb07c4f39c3e8 (Vlastimil Babka             2023-05-23 09:06:34 +0200  171) \nc9f8f1242a4c3 (Vlastimil Babka             2025-02-03 10:28:50 +0100  172) config KVFREE_RCU_BATCHED\nc9f8f1242a4c3 (Vlastimil Babka             2025-02-03 10:28:50 +0100  173) \tdef_bool y\nc9f8f1242a4c3 (Vlastimil Babka             2025-02-03 10:28:50 +0100  174) \tdepends on !SLUB_TINY && !TINY_RCU\nc9f8f1242a4c3 (Vlastimil Babka             2025-02-03 10:28:50 +0100  175) \ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  176) config SLUB_TINY\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  177) \tbool \"Configure for minimal memory footprint\"\n6f110a5e4f997 (Linus Torvalds              2025-04-06 10:00:04 -0700  178) \tdepends on EXPERT && !COMPILE_TEST\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  179) \tselect SLAB_MERGE_DEFAULT\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  180) \thelp\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  181) \t   Configures the slab allocator in a way to achieve minimal memory\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  182) \t   footprint, sacrificing scalability, debugging and other features.\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  183) \t   This is intended only for the smallest system that had used the\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  184) \t   SLOB allocator and is not recommended for systems with more than\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  185) \t   16MB RAM.\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  186) \ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  187) \t   If unsure, say N.\ne240e53ae0abb (Vlastimil Babka             2022-11-14 18:13:45 +0100  188) \n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  189) config SLAB_MERGE_DEFAULT\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  190) \tbool \"Allow slab caches to be merged\"\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  191) \tdefault y\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  192) \thelp\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  193) \t  For reduced kernel memory fragmentation, slab caches can be\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  194) \t  merged when they share the same size and other characteristics.\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  195) \t  This carries a risk of kernel heap overflows being able to\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  196) \t  overwrite objects from merged caches (and more easily control\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  197) \t  cache layout), which makes such heap attacks easier to exploit\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  198) \t  by attackers. By keeping caches unmerged, these kinds of exploits\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  199) \t  can usually only damage objects in the same cache. To disable\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  200) \t  merging at runtime, \"slab_nomerge\" can be passed on the kernel\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  201) \t  command line.\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  202) \n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  203) config SLAB_FREELIST_RANDOM\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  204) \tbool \"Randomize slab freelist\"\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  205) \tdepends on !SLUB_TINY\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  206) \thelp\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  207) \t  Randomizes the freelist order used on creating new pages. This\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  208) \t  security feature reduces the predictability of the kernel slab\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  209) \t  allocator against heap overflows.\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  210) \n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  211) config SLAB_FREELIST_HARDENED\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  212) \tbool \"Harden slab freelist metadata\"\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  213) \tdepends on !SLUB_TINY\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  214) \thelp\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  215) \t  Many kernel heap attacks try to target slab cache metadata and\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  216) \t  other infrastructure. This options makes minor performance\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  217) \t  sacrifices to harden the kernel slab allocator against common\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  218) \t  freelist exploit methods.\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  219) \n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  220) config SLAB_BUCKETS\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  221) \tbool \"Support allocation from separate kmalloc buckets\"\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  222) \tdepends on !SLUB_TINY\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  223) \tdefault SLAB_FREELIST_HARDENED\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  224) \thelp\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  225) \t  Kernel heap attacks frequently depend on being able to create\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  226) \t  specifically-sized allocations with user-controlled contents\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  227) \t  that will be allocated into the same kmalloc bucket as a\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  228) \t  target object. To avoid sharing these allocation buckets,\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  229) \t  provide an explicitly separated set of buckets to be used for\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  230) \t  user-controlled allocations. This may very slightly increase\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  231) \t  memory fragmentation, though in practice it's only a handful\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  232) \t  of extra pages since the bulk of user-controlled allocations\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  233) \t  are relatively long-lived.\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  234) \n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  235) \t  If unsure, say Y.\n67f2df3b82d09 (Kees Cook                   2024-07-01 12:12:59 -0700  236) \n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  237) config SLUB_STATS\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  238) \tdefault n\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  239) \tbool \"Enable performance statistics\"\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  240) \tdepends on SYSFS && !SLUB_TINY\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  241) \thelp\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  242) \t  The statistics are useful to debug slab allocation behavior in\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  243) \t  order find ways to optimize the allocator. This should never be\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  244) \t  enabled for production use since keeping statistics slows down\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  245) \t  the allocator by a few percentage points. The slabinfo command\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  246) \t  supports the determination of the most active slabs to figure\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  247) \t  out which slabs are relevant to a particular load.\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  248) \t  Try running: slabinfo -DA\n0710d0122abc9 (Vlastimil Babka             2022-05-25 13:25:59 +0200  249) \n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  250) config RANDOM_KMALLOC_CACHES\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  251) \tdefault n\n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  252) \tdepends on !SLUB_TINY\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  253) \tbool \"Randomize slab caches for normal kmalloc\"\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  254) \thelp\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  255) \t  A hardening feature that creates multiple copies of slab caches for\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  256) \t  normal kmalloc allocation and makes kmalloc randomly pick one based\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  257) \t  on code address, which makes the attackers more difficult to spray\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  258) \t  vulnerable memory objects on the heap for the purpose of exploiting\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  259) \t  memory vulnerabilities.\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  260) \n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  261) \t  Currently the number of copies is set to 16, a reasonably large value\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  262) \t  that effectively diverges the memory objects allocated for different\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  263) \t  subsystems or modules into different caches, at the expense of a\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  264) \t  limited degree of memory and CPU overhead that relates to hardware and\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  265) \t  system workload.\n3c61529405842 (GONG, Ruiqi                 2023-07-14 14:44:22 +0800  266) \n2a19be61a6515 (Vlastimil Babka             2023-10-02 15:43:03 +0200  267) endmenu # Slab allocator options\n519bcb797907d (Johannes Weiner             2022-05-19 14:08:53 -0700  268) \n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  269) config SHUFFLE_PAGE_ALLOCATOR\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  270) \tbool \"Page allocator randomization\"\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  271) \tdefault SLAB_FREELIST_RANDOM && ACPI_NUMA\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  272) \thelp\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  273) \t  Randomization of the page allocator improves the average\n7b42f1041c98f (Johannes Weiner             2022-05-19 14:08:53 -0700  